return laws.map(law => ({
  json: {
    ...law,
    url: `https://laws.boe.gov.sa/BoeLaws/Laws/LawDetails/${law.law_id}/1`,
    source: 'laws.boe.gov.sa'
  }
}));

// فحص ChromaDB للقوانين الموجودة
const CHROMADB = 'http://chromadb:8000/api/v1';
const COLLECTION_NAME = 'saleh_knowledge';

// Get collection ID
const cols = await fetch(`${CHROMADB}/collections`).then(r => r.json());
const col = cols.find(c => c.name === COLLECTION_NAME);
if (!col) throw new Error('Collection not found!');

// Get all metadatas
const total = await fetch(`${CHROMADB}/collections/${col.id}/count`).then(r => r.json());
const data = await fetch(`${CHROMADB}/collections/${col.id}/get`, {
  method: 'POST',
  headers: {'Content-Type': 'application/json'},
  body: JSON.stringify({ include: ['metadatas'], limit: total })
}).then(r => r.json());

// Build set of existing law_ids and law_names
const existingIds = new Set();
const existingNames = new Set();
for (const meta of (data.metadatas || [])) {
  if (meta.law_id) existingIds.add(meta.law_id);
  if (meta.law_name) existingNames.add(meta.law_name);
}

// Filter only missing laws
const allLaws = $input.all();
const missing = allLaws.filter(item => {
  const law = item.json;
  return !existingIds.has(law.law_id) && !existingNames.has(law.law_name);
});

if (missing.length === 0) {
  return [{ json: { status: 'up_to_date', message: '✅ جميع القوانين محدثة! لا يوجد ناقص.', total_in_db: total, checked: allLaws.length } }];
}

// Log what we found
console.log(`Found ${missing.length} missing laws out of ${allLaws.length}`);
return missing;

// استخراج نص القانون وتقسيمه
const chunkSize = 800;
const overlap = 100;
const results = [];

const batchNode = $('🔄 معالجة واحد تلو الآخر');
const meta = batchNode.item.json;
const lawName = meta.law_name || 'unknown';
const lawId = meta.law_id || 'unknown';
const source = meta.source || 'boe.gov.sa';
const category = meta.category || 'general';

let html = '';
if (typeof $json === 'string') html = $json;
else if ($json.data && typeof $json.data === 'string') html = $json.data;
else html = JSON.stringify($json);

// تنظيف HTML
let text = html.replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '');
text = text.replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '');
text = text.replace(/<[^>]+>/g, ' ');
text = text.replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&quot;/g, '"');
text = text.replace(/\s+/g, ' ').trim();

const markers = ['نـــص النظـــام', 'نص النظام', 'المادة الأولى'];
for (const m of markers) {
  const idx = text.indexOf(m);
  if (idx > -1) { text = text.substring(idx); break; }
}

for (const m of ['جميع الحقوق محفوظة', 'go to top', 'Additional Links']) {
  const idx = text.indexOf(m);
  if (idx > -1) text = text.substring(0, idx);
}
text = text.trim();

if (text.length < 100) {
  return [{ json: { error: `النص قصير جداً: ${lawName}`, length: text.length, law_name: lawName } }];
}

let start = 0, chunkIdx = 0;
while (start < text.length) {
  const end = Math.min(start + chunkSize, text.length);
  const chunk = text.substring(start, end).trim();
  if (chunk.length > 50) {
    results.push({
      json: {
        chunk_id: `boe_${category}_${lawId.substring(0,8)}_c${chunkIdx}`,
        chunk_text: chunk,
        law_name: lawName,
        law_id: lawId,
        source: source,
        category: category,
        chunk_index: chunkIdx,
        total_text_length: text.length
      }
    });
    chunkIdx++;
  }
  if (end >= text.length) break;
  start += chunkSize - overlap;
}

return results;

const embedding = $json.embedding;
const prev = $('✂️ استخراج وتقسيم النص').item.json;

return {
  ids: [prev.chunk_id],
  embeddings: [embedding],
  documents: [prev.chunk_text],
  metadatas: [{
    law_name: prev.law_name,
    law_id: prev.law_id,
    source: prev.source,
    category: prev.category,
    chunk_index: prev.chunk_index,
    ingested_at: new Date().toISOString(),
    auto_updated: 'true'
  }],
  chunk_id: prev.chunk_id,
  law_name: prev.law_name
};

// تقرير نهائي
const items = $input.all();
const successCount = items.filter(i => !i.json.error).length;
const errorCount = items.filter(i => i.json.error).length;
const timestamp = new Date().toISOString();

// Get final count from ChromaDB
let finalCount = 'N/A';
try {
  const resp = await fetch('http://chromadb:8000/api/v1/collections/86fce70f-0753-4989-9e4c-54d1ded405cd/count');
  finalCount = await resp.json();
} catch(e) {}

return [{
  json: {
    status: 'completed',
    total_chunks_saved: successCount,
    errors: errorCount,
    chromadb_total: finalCount,
    message: `✅ تم حفظ ${successCount} قطعة جديدة في ChromaDB | أخطاء: ${errorCount} | الإجمالي: ${finalCount}`,
    timestamp: timestamp
  }
}];
